/**
 *
 * @param property
 */
export async function loadManifestPlainJs(property) {
    if (typeof property === 'function') {
        // Promise function (dynamic import)
        const result = await property();
        if (typeof result === 'object' && result != null) {
            return result;
        }
    }
    else if (typeof property === 'string') {
        // Import string
        const result = await import(/* @vite-ignore */ property);
        if (typeof result === 'object' && result != null) {
            return result;
        }
    }
    else if (typeof property === 'object' && property != null) {
        // Already resolved module object (statically imported)
        return property;
    }
    return undefined;
}
